import {
  html,
  customElement,
  state,
  unsafeHTML,
} from "@umbraco-cms/backoffice/external/lit";
import { UmbModalBaseElement } from "@umbraco-cms/backoffice/modal";
import type { FormDesign } from "@umbraco-forms/generated";
import type {
  UmbTreeElement,
  UmbTreeItemModelBase,
} from "@umbraco-cms/backoffice/tree";
import { UmbRequestReloadChildrenOfEntityEvent } from "@umbraco-cms/backoffice/entity-action";
import { UMB_ACTION_EVENT_CONTEXT } from "@umbraco-cms/backoffice/action";
import type { UmbEntityUnique } from "@umbraco-cms/backoffice/entity";
import { FormsFormDetailRepository } from "../../../repository/index.js";
import { FORMS_FORM_TREE_ALIAS } from "../../../tree/manifests.js";
import { FORMS_FORM_FOLDER_ENTITY_TYPE, FORMS_FORM_ROOT_ENTITY_TYPE } from "../../../entities.js";
import type { FormsFormMoveOptionsModalData } from "./index.js";

@customElement("forms-form-move-options-modal")
export class FormsFormMoveOptionsModalElement extends UmbModalBaseElement<FormsFormMoveOptionsModalData> {
  #formDetailRepository = new FormsFormDetailRepository(this);

  @state()
  private _formToMove?: FormDesign | null;

  @state()
  private _canSubmit = false;

  async connectedCallback() {
    super.connectedCallback();

    if (!this.data?.unique) return;
    const { data } = await this.#formDetailRepository.requestByUnique(
      this.data.unique
    );
    this._formToMove = data;
  }

  #onMoveToFolderSelectionChange() {
    const moveToFolderSelection = this.#getMoveToFolderSelection();
    this._canSubmit = moveToFolderSelection !== undefined;
  }

  #getMoveToFolderSelection() {
    const moveToFolderElement = this.shadowRoot?.getElementById(
      "MoveToFolder"
    ) as UmbTreeElement;
    return moveToFolderElement.getSelection()[0];
  }

  async #onSubmit(event: SubmitEvent) {
    event.preventDefault();
    if (!this.#formDetailRepository)
      throw new Error("Repository is not available");
    if (!this.data?.unique)
      throw new Error("Unique identifier is not available");

    const form = event.target as HTMLFormElement;
    if (!form) return;

    const isValid = form.checkValidity();
    if (!isValid) return;

    const moveToFolder = this.#getMoveToFolderSelection();

    const { error } = await this.#formDetailRepository.moveForm(
      this.data.unique,
      moveToFolder
    );

    if (!error) {
      await this.#reloadFolder(this._formToMove?.parentUnique as UmbEntityUnique);
      await this.#reloadFolder(moveToFolder);

      this._submitModal();
    } else {
      this._rejectModal();
    }
  }

  async #reloadFolder(folderId: UmbEntityUnique) {
    const reloadEvent = new UmbRequestReloadChildrenOfEntityEvent({
      entityType: folderId ? FORMS_FORM_FOLDER_ENTITY_TYPE : FORMS_FORM_ROOT_ENTITY_TYPE,
      unique: folderId,
    });

    const eventContext = await this.getContext(UMB_ACTION_EVENT_CONTEXT);
    eventContext.dispatchEvent(reloadEvent);
  }

  render() {
    return html`
      <umb-body-layout headline=${this.localize.term('formMove_formMoveModalHeadline')}>
        <uui-box>
          <p>
            ${unsafeHTML(this.localize.term('formMove_title', this._formToMove?.name))}
          </p>
          <uui-form>
            <form id="MoveForm" @submit="${this.#onSubmit}">
              <uui-form-layout-item>
                <umb-tree
                  id="MoveToFolder"
                  alias="${FORMS_FORM_TREE_ALIAS}"
                  .props=${{
                    hideTreeRoot: false,
                    selectionConfiguration: {
                      multiple: false,
                    },
                    selectableFilter: (item: UmbTreeItemModelBase) =>
                      item.isFolder,
                  }}
                  @selection-change=${this.#onMoveToFolderSelectionChange}
                ></umb-tree>
              </uui-form-layout-item>
            </form>
          </uui-form>
        </uui-box>
        <uui-button
          slot="actions"
          id="cancel"
          label=${this.localize.term("general_cancel")}
          @click="${this._rejectModal}"
          >${this.localize.term("general_cancel")}</uui-button
        >
        <uui-button
          form="MoveForm"
          ?disabled=${!this._canSubmit}
          slot="actions"
          type="submit"
          label=${this.localize.term("formMove_moveButtonLabel")}
          look="primary"
          color="positive"
        ></uui-button>
      </umb-body-layout>
    `;
  }
}

export default FormsFormMoveOptionsModalElement;

declare global {
  interface HTMLElementTagNameMap {
    "forms-form-move-options-modal": FormsFormMoveOptionsModalElement;
  }
}
